import { useState } from 'react';
import axios from 'axios';

const Upload = ({ onUpload }) => {
  const [file, setFile] = useState(null);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    formData.append('file', file);
    try {
      const token = localStorage.getItem('token');
      await axios.post('http://localhost:5000/api/documents/upload', formData, { headers: { Authorization: `Bearer ${token}` } });
      onUpload();
    } catch (err) {
      setError(err.response.data.message);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="max-w-md mx-auto">
      <input type="file" onChange={(e) => setFile(e.target.files[0])} className="w-full p-2 mb-2 border" required />
      {error && <p className="text-red-500">{error}</p>}
      <button type="submit" className="w-full bg-blue-600 text-white p-2">Upload</button>
    </form>
  );
};

export default Upload;
